import akka.actor.ActorSystem
import akka.http.scaladsl.Http
import akka.http.scaladsl.model.{HttpRequest, StatusCodes}
import akka.http.scaladsl.server.Directives._
import akka.http.scaladsl.unmarshalling.Unmarshal
import akka.stream.ActorMaterializer
import scala.concurrent.Future
import scala.concurrent.ExecutionContext.Implicits.global
import java.net.InetAddress

object WebhookProxyService extends App {
  implicit val system = ActorSystem("webhook-proxy-system")
  implicit val materializer = ActorMaterializer()

  val allowlist = Set("https://api.partner1.com", "https://api.partner2.com")

  def isInternalIp(url: String): Boolean = {
    val ip = InetAddress.getByName(new java.net.URL(url).getHost)
    ip.isLoopbackAddress || ip.isLinkLocalAddress || ip.isSiteLocalAddress
  }

  def fetchContent(url: String): Future[String] = {
    if (allowlist.exists(url.startsWith) && !isInternalIp(url)) {
      Http().singleRequest(HttpRequest(uri = url)).flatMap { response =>
        if (response.status.isSuccess()) {
          Unmarshal(response.entity).to[String]
        } else {
          Future.failed(new Exception(s"Failed to fetch content: ${response.status}"))
        }
      }
    } else {
      Future.failed(new Exception("URL not allowed or is an internal IP"))
    }
  }

  val route =
    path("fetch") {
      post {
        entity(as[String]) { userUrl =>
          onComplete(fetchContent(userUrl)) {
            case scala.util.Success(content) => complete(StatusCodes.OK, content)
            case scala.util.Failure(ex) => complete(StatusCodes.BadRequest, ex.getMessage)
          }
        }
      }
    }

  Http().bindAndHandle(route, "localhost", 8080)
}